"use client";

import Image from "next/image";
import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, ArrowRight, Plus } from "lucide-react";

const services = [
  {
    title: "Sales",
    image: "/sales.jpg",
  },
  {
    title: "Sourcing",
    image: "/sourcing.jpg",
  },
  {
    title: "Operations",
    image: "/operations.jpg",
  },
];

export default function ServicesHeroCarousel() {
  const [index, setIndex] = useState(0);

  const total = services.length;

  const nextSlide = () => {
    setIndex((prev) => (prev + 1) % total);
  };

  const prevSlide = () => {
    setIndex((prev) => (prev - 1 + total) % total);
  };

  const visibleSlides = [
    services[index % total],
    services[(index + 1) % total],
    services[(index + 2) % total],
  ];

  return (
    <section className="bg-white py-24 px-6 md:px-16 lg:px-24 overflow-hidden">
      <div className="max-w-7xl mx-auto grid lg:grid-cols-2 gap-16 items-center">

        {/* LEFT CONTENT */}

        <div>
          <p className="text-sm text-black mb-6">
            Your Trusted Trader
          </p>

          <h1 className="text-5xl md:text-6xl font-bold text-[#ffffff] leading-tight">
            Facilitating smoother,
            stress-free negotiations
            is our specialty.
          </h1>

          <button className="flex items-center gap-4 mt-10 group">

            <div className="w-12 h-12 rounded-full bg-[#80994a] flex items-center justify-center text-white">
              <Plus className="group-hover:rotate-90 transition duration-300" />
            </div>

            <span className="text-[#2f4f2f] font-medium">
              View all services
            </span>

          </button>
        </div>

        {/* RIGHT CAROUSEL */}

        <div className="relative">

          {/* Arrows */}

          <div className="absolute -top-16 right-0 flex gap-4 z-10">
            <button
              onClick={prevSlide}
              className="w-12 h-12 rounded-full border border-[#2f4f2f]
              flex items-center justify-center
              text-[#2f4f2f]
              hover:bg-[#2f4f2f]
              hover:text-white
              transition"
            >
              <ArrowLeft size={18} />
            </button>

            <button
              onClick={nextSlide}
              className="w-12 h-12 rounded-full border border-[#2f4f2f]
              flex items-center justify-center
              text-[#2f4f2f]
              hover:bg-[#2f4f2f]
              hover:text-white
              transition"
            >
              <ArrowRight size={18} />
            </button>
          </div>

          {/* Slides */}

          <div className="flex gap-6">
            <AnimatePresence mode="wait">
              {visibleSlides.map((item, i) => (
                <motion.div
                  key={index + i}
                  initial={{ opacity: 0, x: 80 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -80 }}
                  transition={{ duration: 0.6 }}
                  className="min-w-[240px]"
                >
                  <div className="overflow-hidden rounded-xl">

                    <Image
                      src={item.image}
                      alt={item.title}
                      width={260}
                      height={340}
                      className="object-cover w-[260px] h-[340px]
                      transition duration-500 hover:scale-110"
                      priority
                    />

                  </div>

                  <div className="flex items-center gap-2 mt-4
                  text-[#2f4f2f] font-semibold">
                    {item.title}
                    <span>→</span>
                  </div>

                </motion.div>
              ))}
            </AnimatePresence>
          </div>

        </div>

      </div>
    </section>
  );
}